import{c as t,S as a,j as o,m as n}from"./chunks/framework.DvQr6YbT.js";const u=JSON.parse('{"title":"Guides","description":"","frontmatter":{},"headers":[],"relativePath":"guides/index.md","filePath":"guides/index.md","lastUpdated":1783065655000}'),r={name:"guides/index.md"};function i(s,e,l,d,h,c){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="guides" tabindex="-1">Guides <a class="header-anchor" href="#guides" aria-label="Permalink to “Guides”">​</a></h1><p>These guides cover the everyday workflows that Knowlery supports.</p><h2 id="initialize-a-vault" tabindex="-1">Initialize a Vault <a class="header-anchor" href="#initialize-a-vault" aria-label="Permalink to “Initialize a Vault”">​</a></h2><ol><li>Open the command palette.</li><li>Run <strong>Knowlery: Initialize vault</strong>.</li><li>Choose Claude Code or OpenCode.</li><li>Review the files, skills, and configuration Knowlery will create.</li><li>Optionally select missing tool preparation steps.</li><li>Run setup.</li><li>Open the dashboard when setup completes.</li></ol><p>Use a test vault first if you are evaluating Knowlery. Setup writes several top-level files and folders.</p><h2 id="read-the-dashboard" tabindex="-1">Read the Dashboard <a class="header-anchor" href="#read-the-dashboard" aria-label="Permalink to “Read the Dashboard”">​</a></h2><p>Knowlery now centers on one action-first dashboard:</p><table tabindex="0"><thead><tr><th>Section</th><th>What to do there</th></tr></thead><tbody><tr><td>Today&#39;s move</td><td>Start with the current activity state and pick one small next move</td></tr><tr><td>Suggested moves</td><td>Copy or send reusable prompts such as Process new material, Connect related notes, Challenge an idea, Fix note metadata, or Draft an output</td></tr><tr><td>Knowledge health</td><td>Open Freshness Review when suggestions are waiting</td></tr><tr><td>This note</td><td>Review the active Markdown note and ask for related connections</td></tr><tr><td>Recent activity</td><td>Inspect recent private activity receipts</td></tr><tr><td>This week</td><td>Generate a weekly summary or send a polish request</td></tr><tr><td>Bundles</td><td>Share a reviewed knowledge bundle or install one from someone else</td></tr></tbody></table><p>Use the refresh button when recent activity or vault changes need to be reflected. Use <strong>View all</strong> links for longer move and activity lists.</p><h2 id="work-with-today-s-move" tabindex="-1">Work with Today&#39;s Move <a class="header-anchor" href="#work-with-today-s-move" aria-label="Permalink to “Work with Today&#39;s Move”">​</a></h2><p>Today&#39;s move is the quickest way to understand what Knowlery thinks is happening in your vault.</p><ol><li>Open the dashboard.</li><li>Read the current summary and the highlighted next move.</li><li>Use the copy or send action if you want an agent prompt.</li><li>Use Add reflection if you want to record a private note about your own work.</li></ol><p>If you already have activity receipts, Knowlery will show active knowledge threads and likely next moves. If you do not, it will steer you toward the first cook or a small setup step.</p><h2 id="review-a-note" tabindex="-1">Review a Note <a class="header-anchor" href="#review-a-note" aria-label="Permalink to “Review a Note”">​</a></h2><p>Open a Markdown note and look at the This note section on the dashboard.</p><p>Knowlery will try to identify the active note, relate it to recent knowledge activity, and prepare a focused prompt. Use this when you want to ask an agent to connect one note to older material, comparisons, or reusable structures.</p><h2 id="generate-a-weekly-summary" tabindex="-1">Generate a Weekly Summary <a class="header-anchor" href="#generate-a-weekly-summary" aria-label="Permalink to “Generate a Weekly Summary”">​</a></h2><p>Use This week when you want a broader summary.</p><ol><li>Use <strong>Generate summary</strong> to create a local HTML report in <code>.knowlery/reports/latest.html</code>.</li><li>Use <strong>Open last report</strong> to open that file outside Obsidian.</li><li>Use <strong>Send for review</strong> when you want a companion agent to write a more polished review summary.</li><li>Use <strong>Check result</strong> to refresh the request/result state.</li></ol><p>The report also saves a dated snapshot under <code>.knowlery/reports/weekly/</code>.</p><h2 id="use-suggested-moves" tabindex="-1">Use Suggested Moves <a class="header-anchor" href="#use-suggested-moves" aria-label="Permalink to “Use Suggested Moves”">​</a></h2><p>Suggested moves are the place to start from product-language actions instead of raw skill names.</p><p>The move catalog includes:</p><table tabindex="0"><thead><tr><th>Move</th><th>What it is for</th></tr></thead><tbody><tr><td>Process new material</td><td>Turn rough notes, clips, or conversations into durable knowledge pages</td></tr><tr><td>Connect related notes</td><td>Find older notes, adjacent themes, and reusable patterns</td></tr><tr><td>Challenge an idea</td><td>Check assumptions, missing evidence, counterexamples, and risks</td></tr><tr><td>Fix note metadata</td><td>Review drift, duplicates, frontmatter gaps, broken links, and index hygiene</td></tr><tr><td>Draft an output</td><td>Turn a mature topic into a checklist, outline, template, proposal, or decision memo</td></tr></tbody></table><p>Open a move to copy its prompt or send it to your configured agent chat. Open <strong>Settings -&gt; Knowlery -&gt; Skills</strong> to inspect, create, fork, edit, disable, or delete the underlying skills.</p><h3 id="recommended-skill-flow" tabindex="-1">Recommended Skill Flow <a class="header-anchor" href="#recommended-skill-flow" aria-label="Permalink to “Recommended Skill Flow”">​</a></h3><table tabindex="0"><thead><tr><th>Goal</th><th>Skill</th></tr></thead><tbody><tr><td>Process raw notes</td><td><code>cook</code></td></tr><tr><td>Ask what the vault already knows</td><td><code>ask</code></td></tr><tr><td>Find bridges between topics</td><td><code>explore</code></td></tr><tr><td>Review assumptions</td><td><code>challenge</code></td></tr><tr><td>Generate synthesis ideas</td><td><code>ideas</code></td></tr><tr><td>Check for structural problems</td><td><code>audit</code></td></tr><tr><td>Clean up organization</td><td><code>organize</code></td></tr></tbody></table><h2 id="share-a-knowledge-bundle" tabindex="-1">Share a Knowledge Bundle <a class="header-anchor" href="#share-a-knowledge-bundle" aria-label="Permalink to “Share a Knowledge Bundle”">​</a></h2><p>Use <strong>Share knowledge bundle</strong> (command palette or the Bundles section on the dashboard) when you want to give someone else a reviewed slice of your knowledge.</p><ol><li>Pick a seed topic. Knowlery collects the graph-closure of connected knowledge pages and cited raw sources.</li><li>Review every item in scope. Each page and source is unreviewed, approved, or flagged — nothing ships until you approve it.</li><li>Check the automated risk scan. It highlights emails, sensitive URLs, person pages, and meeting-like notes before export.</li><li>Confirm the bundle metadata (id, title, version, creator, license) and options.</li><li>Export. The bundle is written under <code>.knowlery/exports/</code> and can be saved as a <code>.zip</code> for sharing.</li></ol><p>The exported bundle contains the approved pages, an <code>index.md</code> and <code>agent-index.json</code> for navigation, approved raw sources under <code>_sources/</code>, an update log, and a README for the recipient. If &quot;Include SCHEMA.md&quot; is on, the shipped schema is scoped to the tags and domains the exported pages actually use — never your vault-wide taxonomy.</p><p>Each topic keeps its own saved review scope, so working on one bundle never disturbs another.</p><h2 id="install-a-knowledge-bundle" tabindex="-1">Install a Knowledge Bundle <a class="header-anchor" href="#install-a-knowledge-bundle" aria-label="Permalink to “Install a Knowledge Bundle”">​</a></h2><p>Use <strong>Install knowledge bundle</strong> (command palette or the dashboard card) to add a bundle someone shared with you.</p><ol><li>Choose the bundle <code>.zip</code> or folder.</li><li>Review the manifest and conformance preview before anything is written.</li><li>Install. The bundle lands in <code>Library/&lt;bundle-id&gt;/</code> and is registered in <code>.knowlery/bundles.json</code>.</li></ol><p>Installed bundles are listed on the dashboard, where they can also be uninstalled. Installing adds a retrieval pointer to <code>KNOWLEDGE.md</code>, and the <code>/ask</code> skill checks installed bundles explicitly when answering questions. Updates require a newer bundle version; installing past a conformance failure requires explicit acknowledgement.</p><p>When you want to make an installed bundle page your own, use <strong>Fork to my knowledge</strong> from the file menu on a bundle concept page — it copies the page into your own knowledge directories.</p><h2 id="add-or-edit-rules" tabindex="-1">Add or Edit Rules <a class="header-anchor" href="#add-or-edit-rules" aria-label="Permalink to “Add or Edit Rules”">​</a></h2><p>Rules guide agent behavior in this vault.</p><ol><li>Open <strong>Settings -&gt; Knowlery</strong>.</li><li>Use <strong>Add rule</strong> to create a new rule.</li><li>Give the rule a focused filename and title.</li><li>Write plain markdown instructions.</li><li>Save and verify the rule appears in the rules list.</li></ol><p>Good rules are short and enforceable. Prefer “Always cite source notes using wikilinks” over a broad essay about writing style.</p><h2 id="switch-platforms" tabindex="-1">Switch Platforms <a class="header-anchor" href="#switch-platforms" aria-label="Permalink to “Switch Platforms”">​</a></h2><p>Use the settings tab to switch between Claude Code and OpenCode.</p><p>Knowlery will:</p><ul><li>Create the target rules directory if needed.</li><li>Copy markdown rule files from the old platform directory to the new one.</li><li>Regenerate the platform configuration file.</li><li>Optionally clean up the previous platform config.</li></ul><p>Review generated config after switching platforms, especially if you have custom rules.</p><h2 id="run-a-health-diagnosis" tabindex="-1">Run a Health Diagnosis <a class="header-anchor" href="#run-a-health-diagnosis" aria-label="Permalink to “Run a Health Diagnosis”">​</a></h2><p>Open <strong>Settings -&gt; Knowlery</strong>, then use the Diagnostics section and click <strong>Run diagnosis</strong>.</p><p>Knowlery checks:</p><ul><li>Orphan notes with no incoming wikilinks.</li><li>Broken wikilinks that do not resolve to existing files.</li><li>Missing frontmatter in <code>entities/</code>, <code>concepts/</code>, <code>comparisons/</code>, and <code>queries/</code>.</li></ul><p>Health output is advisory. Review findings before restructuring a real vault.</p><h2 id="run-freshness-review" tabindex="-1">Run Freshness Review <a class="header-anchor" href="#run-freshness-review" aria-label="Permalink to “Run Freshness Review”">​</a></h2><p>Use Freshness Review when you want an agent to check whether compiled knowledge pages are outdated or superseded.</p><ol><li>Open Knowledge health from the dashboard.</li><li>Use <strong>Prepare request</strong> to write a request JSON file under <code>.knowlery/freshness/requests/</code>.</li><li>Copy the prompt and run the agent separately.</li><li>Put the result JSON where the request asks, then use <strong>Import results</strong>.</li><li>Review each suggestion before applying, dismissing, or marking it incorrect.</li></ol><p>Knowlery only patches scalar freshness frontmatter after approval. It does not call a model API for this workflow.</p><h2 id="capture-reflection" tabindex="-1">Capture Reflection <a class="header-anchor" href="#capture-reflection" aria-label="Permalink to “Capture Reflection”">​</a></h2><p>Use <strong>Add reflection</strong> from the command palette or dashboard when you want to capture a private summary of what happened in an agent session or a manual review.</p><p>The reflection lives in the Activity Ledger, not in a normal vault note.</p><h2 id="regenerate-agent-config" tabindex="-1">Regenerate Agent Config <a class="header-anchor" href="#regenerate-agent-config" aria-label="Permalink to “Regenerate Agent Config”">​</a></h2><p>If your agent instructions drift or a config file is accidentally edited, use the settings tab to regenerate platform config.</p><p>This is useful after changing the knowledge base name, switching platforms, or repairing a partially initialized vault.</p><h2 id="work-safely-with-agents" tabindex="-1">Work Safely With Agents <a class="header-anchor" href="#work-safely-with-agents" aria-label="Permalink to “Work Safely With Agents”">​</a></h2><p>Use these conventions when asking an agent to work in a Knowlery vault:</p><ul><li>Ask the agent to read <code>KNOWLEDGE.md</code> first.</li><li>Keep source notes separate from compiled knowledge pages.</li><li>Ask for citations with <code>[[wikilinks]]</code>.</li><li>Review generated knowledge pages before relying on them.</li><li>Run Health after large imports, migrations, or agent-generated changes.</li></ul>',64)])])}const g=t(r,[["render",i]]);export{u as __pageData,g as default};
